import java.util.Arrays;
import java.util.HashMap;
import java.util.HashSet;

class Solution {
    public static String solve(String x) {
        HashMap<Character, Integer> counts = new HashMap<>();
        int maxCount = 0;
        char maxChar = x.charAt(0);
        for (char c : x.toCharArray()) {
            if (c == ' ') continue;
            int count = counts.getOrDefault(c, 0) + 1;
            counts.put(c, count);
            if (count > maxCount) {
                maxCount = count;
                maxChar = c;
            }
        }
        return String.valueOf(maxChar);
    }
}
